INSERT INTO tunes (id, slug, name, share_code, car_id, tune_type, pi_class, pi_score, drivetrain, power_hp, weight_lb, description, tune_values, author_handle, edit_password_hash, ip_hash, rating_sum, rating_count, download_count, status, created_at, updated_at) VALUES
  (1, 'toyota-sprinter-trueno-ae86-1986-demo01', '秋名山下り Spec', '821-471-933', 9, 'touge', 'A', 800, 'RWD', 240, 2050, '經典峠道下坡設定。後輪偏軟、前防傾桿吃硬讓車頭咬入，靠重量轉移過彎不靠輪胎抓地力。煞車前傾 56%，方便用煞車塞進角。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'takumi_fan', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 47, 11, 2840, 'public', 1779582011, 1779582011),
  (2, 'nissan-silvia-s15-1998-demo02', 'Weekend Sideways', '442-189-007', 5, 'drift', 'A', 798, 'RWD', 480, 2680, 'S15 漂移基礎設定。差速器加速 100% 全鎖、後輪壓力刻意降到 26 psi 增加可控滑動。前束 -0.5 給回正速度。新手友善版。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'silvia_lover', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 38, 9, 4120, 'public', 1779582011, 1779582011),
  (3, 'nissan-skyline-gtr-r34-1999-demo03', 'Bayshore Hunter', '999-061-345', 3, 'grip', 'S1', 898, 'AWD', 720, 3380, 'R34 灣岸高速設定，前後比例偏 40/60 讓 ATTESA 在直線釋放更多後輪動力。終傳拉長到 3.62，250 mph 直線王。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'wangan_runner', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 52, 12, 6720, 'public', 1779582011, 1779582011),
  (4, 'toyota-supra-mk4-1994-demo04', '2JZ 1500 Snake', '707-202-815', 10, 'drag', 'S2', 980, 'RWD', 1520, 3210, '2JZ 暴力直線。前空力 0，後尾翼最大，4-6 檔拉長。差速器加速鎖死 100%，起步靠 launch control。1/4 哩 7.8 秒。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'two_j_zee', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 41, 9, 5240, 'public', 1779582011, 1779582011),
  (5, 'subaru-impreza-22b-sti-1998-demo05', 'Group A Tribute', '356-118-902', 27, 'rally', 'A', 800, 'AWD', 380, 2980, '22B 拉力致敬設定。前後 50/50 鎖定，砂石路面車高 +0.6 in，胎壓降到 24 psi 抓地。獻給 Colin McRae。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'wrc_dreamer', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 33, 8, 3180, 'public', 1779582011, 1779582011),
  (6, 'mazda-mx5-miata-na-1989-demo06', 'Lightweight Touge', '128-444-657', 18, 'touge', 'C', 598, 'RWD', 165, 2080, 'NA Miata 極簡設定。彈簧最軟讓重量轉移完整、空力歸零、差速器加速 28%。115 馬力跟你說車重才是王道。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'miata_is_always_the_answer', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 39, 9, 1840, 'public', 1779582011, 1779582011),
  (7, 'honda-civic-type-r-ek9-1997-demo07', 'FF King EK9', '614-993-021', 20, 'grip', 'A', 780, 'FWD', 280, 2410, '前驅抓地調校。前防傾桿吃滿、後輪反而軟、前負外傾 -3.2°。轉向過度但只要敢踩油就把車頭甩回來。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'k20_swap', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 28, 7, 2210, 'public', 1779582011, 1779582011),
  (8, 'ford-f150-raptor-r-2023-demo08', 'Desert Dominator', '551-770-184', 48, 'offroad', 'S1', 880, 'AWD', 780, 5950, '沙漠飛車設定。車高拉到 +2.0、壓縮阻尼放軟、空力歸零。著陸超穩，跳完還能繼續油門到底。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'baja_runner', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 22, 6, 1450, 'public', 1779582011, 1779582011),
  (9, 'dodge-challenger-srt-demon-2018-demo09', '1/4 Mile Demon', '666-001-911', 50, 'drag', 'X', 999, 'RWD', 1840, 4280, 'Demon 直線怪物。前空力全卸、後翼歸零、6 檔終速 280 mph。Wheelie bar 模擬：前彈簧最硬避免翹頭。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'hellcat_x', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 19, 5, 3340, 'public', 1779582011, 1779582011),
  (10, 'porsche-cayman-gt4-rs-2022-demo10', 'Green Hell Cayman', '997-247-650', 35, 'grip', 'S2', 945, 'RWD', 520, 3120, 'GT4 RS 紐柏林設定。前空力 ±0、後翼最大、空力分配 47/53。低速 Karussell 過彎不會推、高速 Schwedenkreuz 不會浮。', '{"tires":{"pressure_f":28.5,"pressure_r":30},"gearing":{"final":3.97,"g1":3.21,"g2":2.18,"g3":1.56,"g4":1.2,"g5":0.97,"g6":0.79},"alignment":{"camber_f":-2.4,"camber_r":-1.8,"toe_f":-0.1,"toe_r":0.2,"caster":6.2},"antiroll":{"stiffness_f":28.5,"stiffness_r":22},"springs":{"rate_f":685,"rate_r":520,"height_f":4.4,"height_r":4.5},"damping":{"rebound_f":9.4,"rebound_r":7.1,"bump_f":3.8,"bump_r":2.6},"aero":{"front":155,"rear":204},"brakes":{"balance_pct_f":52,"pressure_pct":115},"diff":{"accel_pct":42,"decel_pct":18}}', 'green_hell_jp', '$2b$10$ImW7ciQQwBo2YsnnK1Ic1.m0Ee4KyXVGgoJm0MLDmXsqXYKnH96bi', 'demoseedipdemoseedipdemoseedipde', 44, 10, 2680, 'public', 1779582011, 1779582011);
INSERT INTO reviews (id, tune_id, author_handle, rating, body, ip_hash, status, created_at) VALUES
  (1, 1, 'koganei_rs', 5, '排煙管聲音不會騙人，這就是 86 該有的感覺。', 'demoseedipdemoseedipdemoseedipde', 'public', 1779574811),
