  (3, 1, 'eight_six', 5, 'Akina 下坡 PB -2.3s，神！', 'demoseedipdemoseedipdemoseedipde', 'public', 1779567611),
  (4, 2, 'tandem_king', 5, '雙人連流超穩，推薦給漂移新手練習。', 'demoseedipdemoseedipdemoseedipde', 'public', 1779564011),
  (5, 2, 'drift_otaku', 4, '長彎要留意油門，否則容易抓回來。', 'demoseedipdemoseedipdemoseedipde', 'public', 1779560411),
